// Format Slack message from webhook payload
const input = $json.body || $json;

// Determine message type and format accordingly
const eventType = input.event_type || 'call_completed';
const outcome = input.outcome || 'unknown';

// Emoji and color based on outcome
const outcomeConfig = {
  success: { emoji: '✅', color: '#36a64f' },
  failure: { emoji: '❌', color: '#dc3545' },
  incomplete: { emoji: '⚠️', color: '#ffc107' },
  unknown: { emoji: '❓', color: '#6c757d' }
};

const config = outcomeConfig[outcome] || outcomeConfig.unknown;

// Build the Slack message blocks
const slackPayload = {
  blocks: [
    {
      type: 'header',
      text: {
        type: 'plain_text',
        text: `${config.emoji} Voice Agent Call ${outcome.toUpperCase()}`,
        emoji: true
      }
    },
    {
      type: 'section',
      fields: [
        {
          type: 'mrkdwn',
          text: `*Agent:*\n${input.agent_name || 'Unknown'}`
        },
        {
          type: 'mrkdwn',
          text: `*Duration:*\n${input.duration_seconds ? Math.floor(input.duration_seconds / 60) + 'm ' + (input.duration_seconds % 60) + 's' : 'N/A'}`
        }
      ]
    },
    {
      type: 'section',
      fields: [
        {
          type: 'mrkdwn',
          text: `*Caller:*\n${input.caller_name || input.caller_phone || 'Unknown'}`
        },
        {
          type: 'mrkdwn',
          text: `*Conversation ID:*\n\`${input.conversation_id || 'N/A'}\``
        }
      ]
    }
  ]
};

// Add summary if available
if (input.summary || input.request_summary) {
  slackPayload.blocks.push({
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Summary:*\n${input.summary || input.request_summary}`
    }
  });
}

// Add errors if present
if (input.errors) {
  slackPayload.blocks.push({
    type: 'section',
    text: {
      type: 'mrkdwn',
      text: `*Errors:*\n\`\`\`${input.errors}\`\`\``
    }
  });
}

// Add divider and timestamp
slackPayload.blocks.push(
  { type: 'divider' },
  {
    type: 'context',
    elements: [
      {
        type: 'mrkdwn',
        text: `Sent at ${new Date().toISOString()}`
      }
    ]
  }
);

return {
  json: {
    slackPayload: slackPayload,
    originalInput: input
  }
};
